    // Function to fetch rule groups from GitHub
    async function fetchRuleGroups() {
        const response = await gmFetch('https://raw.githubusercontent.com/ziIIas/scribetools/refs/heads/main/rules.json');
        if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
        const data = await response.json();

        // Return all rule groups from the file, adding metadata info to each
        if (data.ruleGroups && Array.isArray(data.ruleGroups)) {
            return data.ruleGroups.map(group => ({
                ...group,
                // Include supergroup metadata for reference
                supergroup: {
                    id: data.metadata?.id,
                    title: data.metadata?.title,
                    author: data.metadata?.author,
                    version: data.metadata?.version
                }
            }));
        }

        // Fallback for legacy format (single group)
        return [{
            id: data.metadata?.id || 'unknown',
            title: data.metadata?.title || 'Unknown Rules',
            description: data.metadata?.description || '',
            author: data.metadata?.author || 'Unknown',
            version: data.metadata?.version || '1',
            rules: data.rules || []
        }];
    }

